const ids = $.steps.extractIds.output.messageIds || [];
const iterations = $.steps.fetchDetails.response.iterations || [];
let emails = [];
ids.forEach((id, i) => {
  let subject = 'Unknown';
  let from = 'Unknown';
  let snippet = '';
  if (iterations[i] && iterations[i].getOne && iterations[i].getOne.response) {
    const msg = iterations[i].getOne.response;
    snippet = msg.snippet || '';
    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    headers.forEach(h => {
      if (h.name === 'Subject') subject = h.value || 'No Subject';
      if (h.name === 'From') from = h.value || 'Unknown';
    });
  }
  emails.push({ id: id, subject: subject, from: from, snippet: snippet.slice(0, 200) });
});
let compiled = '';
emails.forEach((e, i) => {
  compiled += (i + 1) + '. ID: ' + e.id + '\n';
  compiled += '   Subject: ' + e.subject + '\n';
  compiled += '   From: ' + e.from + '\n';
  compiled += '   Snippet: ' + e.snippet + '\n\n';
});
return { compiled, emails, count: emails.length };

const d = $.steps.compileEmails.output;
const labels = $.input.labels;
let prompt = 'You are an email classification assistant. Classify each email into exactly ONE of these categories: ' + labels + '.\n\n';
prompt += 'EMAILS (' + d.count + '):\n';
prompt += d.compiled + '\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "classifications": [\n';
prompt += '    { "id": "email_id", "subject": "subject line", "label": "chosen_label", "confidence": 0.95 }\n';
prompt += '  ],\n';
prompt += '  "summary": { "total": 0, "byLabel": { "work": 0, "personal": 0 } }\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiClassify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { classifications: [], summary: { total: 0, byLabel: {} } }; }

const ai = $.steps.parseAI.output;
const cls = ai.classifications || [];
const summary = ai.summary || {};
const byLabel = summary.byLabel || {};

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Gmail Auto-Label Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + cls.length + ' emails* classified' } });

let labelSummary = '';
Object.keys(byLabel).forEach(label => {
  labelSummary += '*' + label + ':* ' + byLabel[label] + '  ';
});
if (labelSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: labelSummary } });
}

const topItems = cls.slice(0, 5);
topItems.forEach(c => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':label: *' + (c.label || 'unknown') + '* — ' + (c.subject || 'No Subject').slice(0, 80) } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail API + Claude AI | One CLI' }] });

const fallback = 'Gmail Auto-Label: ' + cls.length + ' emails classified';
return { blocks, fallback };
